const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
let input = [];
rl.on('line', function(line) {
    input.push(line);
}).on('close', function() {
    let [n, k] = input[0].split(' ').map(Number);
    let arr = input[1].split(' ').map(Number);
    let count = 0;
    for (let i = 0; i < n; i++) {
        if (arr[i] <= k) {
            count++;
        }
    }
    console.log(n - count);
});
